package com.taskflow.entity;

import jakarta.persistence.EntityManager;
import jakarta.persistence.PersistenceContext;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.test.context.ActiveProfiles;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

/**
 * Tests for User entity JPA mappings and constraints.
 *
 * Covers:
 * - JPA annotations (@Entity, @Id, @GeneratedValue, @Column)
 * - Required fields: username, password, displayName
 * - Auto-generated fields: id, createdAt
 * - Username uniqueness constraint
 * - Password field exists in entity (not exposed in responses — tested at controller level)
 */
@DataJpaTest
@ActiveProfiles("test")
@DisplayName("User Entity JPA Tests")
class UserEntityTest {

    @PersistenceContext
    private EntityManager entityManager;

    @Test
    @DisplayName("should persist User with all fields and generate id")
    void shouldPersistUserWithAllFieldsAndGenerateId() {
        User user = new User();
        user.setUsername("testuser");
        user.setPassword("hashedpassword123");
        user.setDisplayName("Test User");

        entityManager.persist(user);
        entityManager.flush();
        entityManager.clear();

        User found = entityManager.find(User.class, user.getId());

        assertThat(found).isNotNull();
        assertThat(found.getId()).isNotNull();
        assertThat(found.getUsername()).isEqualTo("testuser");
        assertThat(found.getPassword()).isEqualTo("hashedpassword123");
        assertThat(found.getDisplayName()).isEqualTo("Test User");
    }

    @Test
    @DisplayName("should auto-generate createdAt timestamp on persist")
    void shouldAutoGenerateCreatedAtOnPersist() {
        User user = new User();
        user.setUsername("timeuser");
        user.setPassword("hashedpassword");
        user.setDisplayName("Time User");

        entityManager.persist(user);
        entityManager.flush();
        entityManager.clear();

        User found = entityManager.find(User.class, user.getId());

        assertThat(found.getCreatedAt()).isNotNull();
    }

    @Test
    @DisplayName("should enforce unique username constraint")
    void shouldEnforceUniqueUsernameConstraint() {
        User user1 = new User();
        user1.setUsername("duplicate");
        user1.setPassword("password1");
        user1.setDisplayName("User One");

        User user2 = new User();
        user2.setUsername("duplicate");
        user2.setPassword("password2");
        user2.setDisplayName("User Two");

        entityManager.persist(user1);
        entityManager.flush();

        assertThatThrownBy(() -> {
            entityManager.persist(user2);
            entityManager.flush();
        }).isInstanceOf(Exception.class); // ConstraintViolationException or PersistenceException
    }

    @Test
    @DisplayName("should not allow null username")
    void shouldNotAllowNullUsername() {
        User user = new User();
        user.setUsername(null);
        user.setPassword("password123");
        user.setDisplayName("No Username");

        assertThatThrownBy(() -> {
            entityManager.persist(user);
            entityManager.flush();
        }).isInstanceOf(Exception.class);
    }

    @Test
    @DisplayName("should not allow null password")
    void shouldNotAllowNullPassword() {
        User user = new User();
        user.setUsername("nopassuser");
        user.setPassword(null);
        user.setDisplayName("No Password");

        assertThatThrownBy(() -> {
            entityManager.persist(user);
            entityManager.flush();
        }).isInstanceOf(Exception.class);
    }

    @Test
    @DisplayName("should auto-generate id using identity or sequence strategy")
    void shouldAutoGenerateId() {
        User user1 = new User();
        user1.setUsername("user_a");
        user1.setPassword("password");
        user1.setDisplayName("User A");

        User user2 = new User();
        user2.setUsername("user_b");
        user2.setPassword("password");
        user2.setDisplayName("User B");

        entityManager.persist(user1);
        entityManager.persist(user2);
        entityManager.flush();

        assertThat(user1.getId()).isNotNull();
        assertThat(user2.getId()).isNotNull();
        assertThat(user1.getId()).isNotEqualTo(user2.getId());
    }
}

package com.taskflow.repository;

import com.taskflow.entity.User;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
import org.springframework.test.context.ActiveProfiles;

import java.util.Optional;

import static org.assertj.core.api.Assertions.assertThat;

/**
 * Tests for UserRepository custom query methods.
 *
 * Covers:
 * - findByUsername: happy path, not found, case sensitivity
 */
@DataJpaTest
@ActiveProfiles("test")
@DisplayName("UserRepository Tests")
class UserRepositoryTest {

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private TestEntityManager entityManager;

    private User savedUser;

    @BeforeEach
    void setUp() {
        User user = new User();
        user.setUsername("john_doe");
        user.setPassword("hashed_password");
        user.setDisplayName("John Doe");
        savedUser = entityManager.persistFlushFind(user);
    }

    @Test
    @DisplayName("should find user by username when user exists")
    void shouldFindUserByUsernameWhenUserExists() {
        Optional<User> found = userRepository.findByUsername("john_doe");

        assertThat(found).isPresent();
        assertThat(found.get().getUsername()).isEqualTo("john_doe");
        assertThat(found.get().getDisplayName()).isEqualTo("John Doe");
        assertThat(found.get().getId()).isEqualTo(savedUser.getId());
    }

    @Test
    @DisplayName("should return empty when username does not exist")
    void shouldReturnEmptyWhenUsernameDoesNotExist() {
        Optional<User> found = userRepository.findByUsername("nonexistent");

        assertThat(found).isEmpty();
    }

    @Test
    @DisplayName("should return empty when username is null")
    void shouldReturnEmptyWhenUsernameIsNull() {
        Optional<User> found = userRepository.findByUsername(null);

        assertThat(found).isEmpty();
    }

    @Test
    @DisplayName("should find correct user among multiple users")
    void shouldFindCorrectUserAmongMultipleUsers() {
        User user2 = new User();
        user2.setUsername("jane_doe");
        user2.setPassword("another_hash");
        user2.setDisplayName("Jane Doe");
        entityManager.persistAndFlush(user2);

        Optional<User> found = userRepository.findByUsername("jane_doe");

        assertThat(found).isPresent();
        assertThat(found.get().getUsername()).isEqualTo("jane_doe");
        assertThat(found.get().getDisplayName()).isEqualTo("Jane Doe");
    }
}

package com.taskflow.security;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

/**
 * Unit tests for JwtTokenProvider.
 *
 * No Spring context needed — instantiate directly with constructor args.
 * Expected constructor: JwtTokenProvider(String secret, long expirationMs)
 *
 * Covers:
 * - Token generation: contains userId claim, is non-empty
 * - Token parsing: extract userId from valid token
 * - Token validation: valid token returns true
 * - Expired token detection
 * - Malformed/invalid token handling
 * - Null/empty token handling
 */
@DisplayName("JwtTokenProvider Unit Tests")
class JwtTokenProviderTest {

    private static final String SECRET = "test-jwt-secret-key-must-be-at-least-256-bits-long-for-HS256";
    private static final long EXPIRATION_MS = 86400000L; // 24 hours
    private static final long SHORT_EXPIRATION_MS = 1L; // 1ms for expiry tests

    private JwtTokenProvider tokenProvider;

    @BeforeEach
    void setUp() {
        tokenProvider = new JwtTokenProvider(SECRET, EXPIRATION_MS);
    }

    @Nested
    @DisplayName("Token Generation")
    class TokenGeneration {

        @Test
        @DisplayName("should generate non-empty token for valid userId")
        void shouldGenerateNonEmptyTokenForValidUserId() {
            String token = tokenProvider.generateToken(1L);

            assertThat(token).isNotNull().isNotEmpty();
        }

        @Test
        @DisplayName("should generate different tokens for different userIds")
        void shouldGenerateDifferentTokensForDifferentUserIds() {
            String token1 = tokenProvider.generateToken(1L);
            String token2 = tokenProvider.generateToken(2L);

            assertThat(token1).isNotEqualTo(token2);
        }

        @Test
        @DisplayName("should generate token that contains three parts separated by dots")
        void shouldGenerateTokenWithThreePartsJwtFormat() {
            String token = tokenProvider.generateToken(1L);

            String[] parts = token.split("\\.");
            assertThat(parts).hasSize(3); // header.payload.signature
        }
    }

    @Nested
    @DisplayName("Token Parsing")
    class TokenParsing {

        @Test
        @DisplayName("should extract userId from valid token")
        void shouldExtractUserIdFromValidToken() {
            Long userId = 42L;
            String token = tokenProvider.generateToken(userId);

            Long extractedId = tokenProvider.getUserIdFromToken(token);

            assertThat(extractedId).isEqualTo(userId);
        }

        @Test
        @DisplayName("should extract correct userId for different users")
        void shouldExtractCorrectUserIdForDifferentUsers() {
            String token1 = tokenProvider.generateToken(1L);
            String token2 = tokenProvider.generateToken(999L);

            assertThat(tokenProvider.getUserIdFromToken(token1)).isEqualTo(1L);
            assertThat(tokenProvider.getUserIdFromToken(token2)).isEqualTo(999L);
        }
    }

    @Nested
    @DisplayName("Token Validation")
    class TokenValidation {

        @Test
        @DisplayName("should return true for valid non-expired token")
        void shouldReturnTrueForValidNonExpiredToken() {
            String token = tokenProvider.generateToken(1L);

            boolean isValid = tokenProvider.validateToken(token);

            assertThat(isValid).isTrue();
        }

        @Test
        @DisplayName("should return false for expired token")
        void shouldReturnFalseForExpiredToken() throws InterruptedException {
            JwtTokenProvider shortLivedProvider = new JwtTokenProvider(SECRET, SHORT_EXPIRATION_MS);
            String token = shortLivedProvider.generateToken(1L);

            // Wait for token to expire
            Thread.sleep(50);

            boolean isValid = shortLivedProvider.validateToken(token);

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for malformed token")
        void shouldReturnFalseForMalformedToken() {
            boolean isValid = tokenProvider.validateToken("not.a.valid.jwt.token");

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for empty token")
        void shouldReturnFalseForEmptyToken() {
            boolean isValid = tokenProvider.validateToken("");

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for null token")
        void shouldReturnFalseForNullToken() {
            boolean isValid = tokenProvider.validateToken(null);

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for token with tampered signature")
        void shouldReturnFalseForTamperedToken() {
            String token = tokenProvider.generateToken(1L);
            // Tamper with the last character of the signature
            String tampered = token.substring(0, token.length() - 1) + (token.endsWith("A") ? "B" : "A");

            boolean isValid = tokenProvider.validateToken(tampered);

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for token signed with different secret")
        void shouldReturnFalseForTokenSignedWithDifferentSecret() {
            JwtTokenProvider otherProvider = new JwtTokenProvider(
                    "different-secret-key-must-also-be-long-enough-for-HS256-algo",
                    EXPIRATION_MS
            );
            String token = otherProvider.generateToken(1L);

            boolean isValid = tokenProvider.validateToken(token);

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for random string")
        void shouldReturnFalseForRandomString() {
            boolean isValid = tokenProvider.validateToken("random-garbage-string");

            assertThat(isValid).isFalse();
        }
    }
}

package com.taskflow.security;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockHttpServletResponse;
import org.springframework.security.core.context.SecurityContextHolder;

import java.io.IOException;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.Mockito.*;

/**
 * Mock-based unit tests for JwtAuthFilter.
 *
 * Tests the OncePerRequestFilter that:
 * - Extracts Bearer token from Authorization header
 * - Validates the token via JwtTokenProvider
 * - Sets SecurityContext authentication on valid token
 * - Passes through (no auth set) on missing/invalid token
 *
 * Uses MockHttpServletRequest/Response to simulate HTTP requests.
 */
@ExtendWith(MockitoExtension.class)
@DisplayName("JwtAuthFilter Unit Tests")
class JwtAuthFilterTest {

    @Mock
    private JwtTokenProvider tokenProvider;

    @Mock
    private FilterChain filterChain;

    private JwtAuthFilter jwtAuthFilter;
    private MockHttpServletRequest request;
    private MockHttpServletResponse response;

    @BeforeEach
    void setUp() {
        jwtAuthFilter = new JwtAuthFilter(tokenProvider);
        request = new MockHttpServletRequest();
        response = new MockHttpServletResponse();
        SecurityContextHolder.clearContext();
    }

    @Nested
    @DisplayName("Valid Token Scenarios")
    class ValidTokenScenarios {

        @Test
        @DisplayName("should set authentication in SecurityContext when valid Bearer token is provided")
        void shouldSetAuthenticationWhenValidBearerToken() throws ServletException, IOException {
            String token = "valid.jwt.token";
            request.addHeader("Authorization", "Bearer " + token);

            when(tokenProvider.validateToken(token)).thenReturn(true);
            when(tokenProvider.getUserIdFromToken(token)).thenReturn(42L);

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNotNull();
            assertThat(SecurityContextHolder.getContext().getAuthentication().isAuthenticated()).isTrue();
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("should extract userId and set it as principal when token is valid")
        void shouldExtractUserIdAndSetAsPrincipal() throws ServletException, IOException {
            String token = "valid.jwt.token";
            request.addHeader("Authorization", "Bearer " + token);

            when(tokenProvider.validateToken(token)).thenReturn(true);
            when(tokenProvider.getUserIdFromToken(token)).thenReturn(42L);

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            Object principal = SecurityContextHolder.getContext().getAuthentication().getPrincipal();
            // The principal should contain or be the userId (42L)
            assertThat(principal.toString()).contains("42");
        }
    }

    @Nested
    @DisplayName("Missing/Invalid Token Scenarios")
    class MissingInvalidTokenScenarios {

        @Test
        @DisplayName("should not set authentication when no Authorization header present")
        void shouldNotSetAuthWhenNoAuthorizationHeader() throws ServletException, IOException {
            // No Authorization header set on request

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNull();
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("should not set authentication when Authorization header has no Bearer prefix")
        void shouldNotSetAuthWhenNoBearerPrefix() throws ServletException, IOException {
            request.addHeader("Authorization", "Basic sometoken");

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNull();
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("should not set authentication when token is invalid")
        void shouldNotSetAuthWhenTokenIsInvalid() throws ServletException, IOException {
            String token = "invalid.jwt.token";
            request.addHeader("Authorization", "Bearer " + token);

            when(tokenProvider.validateToken(token)).thenReturn(false);

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNull();
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("should not set authentication when Authorization header is empty Bearer")
        void shouldNotSetAuthWhenBearerIsEmpty() throws ServletException, IOException {
            request.addHeader("Authorization", "Bearer ");

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNull();
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("should not set authentication when Authorization header is just 'Bearer'")
        void shouldNotSetAuthWhenBearerOnly() throws ServletException, IOException {
            request.addHeader("Authorization", "Bearer");

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNull();
            verify(filterChain).doFilter(request, response);
        }
    }

    @Nested
    @DisplayName("Filter Chain Continuation")
    class FilterChainContinuation {

        @Test
        @DisplayName("should always continue filter chain regardless of token validity")
        void shouldAlwaysContinueFilterChain() throws ServletException, IOException {
            // Case 1: No header
            jwtAuthFilter.doFilterInternal(request, response, filterChain);
            verify(filterChain, times(1)).doFilter(request, response);

            // Case 2: Invalid token
            setUp();
            request.addHeader("Authorization", "Bearer invalid");
            when(tokenProvider.validateToken("invalid")).thenReturn(false);
            jwtAuthFilter.doFilterInternal(request, response, filterChain);
            verify(filterChain, times(1)).doFilter(request, response);
        }

        @Test
        @DisplayName("should not call getUserIdFromToken when token is invalid")
        void shouldNotCallGetUserIdWhenTokenInvalid() throws ServletException, IOException {
            String token = "invalid.token";
            request.addHeader("Authorization", "Bearer " + token);

            when(tokenProvider.validateToken(token)).thenReturn(false);

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            verify(tokenProvider, never()).getUserIdFromToken(any());
        }
    }
}

package com.taskflow.security;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.test.web.servlet.MockMvc;

import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

/**
 * Integration tests for SecurityConfig filter chain configuration.
 *
 * Verifies:
 * - /api/auth/** endpoints are publicly accessible (permitAll)
 * - Other /api/** endpoints require authentication (401 without token)
 * - H2 console is accessible (permitAll)
 * - JWT filter is integrated into the filter chain
 *
 * Uses full Spring Boot context with MockMvc.
 */
@SpringBootTest
@AutoConfigureMockMvc
@ActiveProfiles("test")
@DisplayName("SecurityConfig Integration Tests")
class SecurityConfigIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Nested
    @DisplayName("Public Endpoints (permitAll)")
    class PublicEndpoints {

        @Test
        @DisplayName("should permit POST /api/auth/register without authentication")
        void shouldPermitRegisterWithoutAuth() throws Exception {
            mockMvc.perform(post("/api/auth/register")
                            .contentType("application/json")
                            .content("{\"username\":\"test\",\"password\":\"password123\",\"displayName\":\"Test\"}"))
                    .andExpect(status().isNot(org.hamcrest.Matchers.equalTo(401)));
            // Note: may return 404 if controller not implemented, but NOT 401
        }

        @Test
        @DisplayName("should permit POST /api/auth/login without authentication")
        void shouldPermitLoginWithoutAuth() throws Exception {
            mockMvc.perform(post("/api/auth/login")
                            .contentType("application/json")
                            .content("{\"username\":\"test\",\"password\":\"password123\"}"))
                    .andExpect(status().isNot(org.hamcrest.Matchers.equalTo(401)));
        }
    }

    @Nested
    @DisplayName("Protected Endpoints (require authentication)")
    class ProtectedEndpoints {

        @Test
        @DisplayName("should return 401 for GET /api/tasks without token")
        void shouldReturn401ForTasksWithoutToken() throws Exception {
            mockMvc.perform(get("/api/tasks"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should return 401 for GET /api/auth/me without token")
        void shouldReturn401ForMeWithoutToken() throws Exception {
            mockMvc.perform(get("/api/auth/me"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should return 401 for any /api/** endpoint without token")
        void shouldReturn401ForAnyApiEndpointWithoutToken() throws Exception {
            mockMvc.perform(get("/api/some/protected/resource"))
                    .andExpect(status().isUnauthorized());
        }
    }

    @Nested
    @DisplayName("JWT Filter Integration")
    class JwtFilterIntegration {

        @Test
        @DisplayName("should return 401 when Authorization header has invalid token")
        void shouldReturn401WithInvalidToken() throws Exception {
            mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer invalid.jwt.token"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should return 401 when Authorization header has expired token")
        void shouldReturn401WithExpiredToken() throws Exception {
            // An obviously invalid/expired token
            mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiIxIiwiZXhwIjoxfQ.invalid"))
                    .andExpect(status().isUnauthorized());
        }
    }

    @Nested
    @DisplayName("Stateless Session Policy")
    class StatelessSessionPolicy {

        @Test
        @DisplayName("should not create HTTP session for requests")
        void shouldNotCreateSession() throws Exception {
            mockMvc.perform(get("/api/tasks"))
                    .andExpect(result -> {
                        // Session should not be created for stateless config
                        assertThat(result.getRequest().getSession(false)).isNull();
                    });
        }

        private void assertThat(Object session) {
            // If session was created, it indicates non-stateless behavior
            org.assertj.core.api.Assertions.assertThat(session).isNull();
        }
    }
}

